import { toolError } from "../result.js";
export const noShopify = toolError("Error: no Shopify integration connected.");
export const noThread = toolError("Error: this tool requires a conversation thread.");
export const cancelReasons = ["customer", "fraud", "inventory", "declined", "other"];
export const threadStatuses = ["open", "pending", "closed"];
export function requireShopify(ctx) {
    return ctx.shopify;
}
export function threadContextOf(ctx) {
    const thread = ctx.thread;
    if (!thread)
        return null;
    return { threadId: thread.id, orgId: ctx.orgId, orgName: ctx.orgName };
}
